import{_ as a,c as l,l as n,a as p,t as e,a4 as i,o as r}from"./chunks/framework.CzsDe1xi.js";const h=JSON.parse('{"title":"Mysql表分区","description":"","frontmatter":{"title":"Mysql表分区"},"headers":[],"relativePath":"doc/数据库/Mysql/架构/分区/分区.md","filePath":"packages/doc/src/数据库/Mysql/架构/分区/分区.md","lastUpdated":1711637456000}'),t={name:"doc/数据库/Mysql/架构/分区/分区.md"},c={id:"frontmatter-title",tabindex:"-1"},o=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),b=i(`<ul><li><a href="https://dev.mysql.com/doc/refman/5.7/en/partitioning.html" target="_blank" rel="noreferrer">官方链接</a></li></ul><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>分区表是一个独立的逻辑表，但是底层由多个物理子表组成。对于SQL层 来说是一个完全封装底层实现的黑盒子，对应用是透明的，但是从底层的</p><p>文件系统来看，每一个分区表都有一个使用#分隔命名的表文件。<strong>(表名#P#分区名.ibd)</strong></p><p><a href="https://cloud.tencent.com/product/cdb?from=10680" target="_blank" rel="noreferrer">MySQL</a>实现分区表的方式——对底层表的封装。索引也是按照分区的子表定义的，而没有全局索引。MySQL在创建表时使用PARTITION BY子句定义每个分区存放的数据。在执行查询的时候，优化器会根据分区定义过滤那些没有我们需要数据的分区，这样查询就无须扫描所有分区，只需要查找包含需要数据的分区就可以了。</p><ul><li>一个表最多只能有1024个分区（MySQL5.6之后支持8192个分区）。</li><li>在MySQL 5.1中，分区表达式必须是整数，或者是返回整数的表达式。在MySQL 5.5中，某些场景中可以直接使用列来进行分区。</li><li>如果分区字段中有主键或者唯一索引的列，那么所有主键列和唯一索引列都必须包含进来。</li><li>分区表中无法使用外键约束。</li><li>表非常大以至于无法全部都放在内存中，或者只在表的最后部分有热点数 据，其他均是历史数据。</li><li>分区表的数据更容易维护。例如，想批量删除大量数据可以使用清除整个 分区的方式。另外，还可以对一个独立分区进行优化、检查、修复等操作。</li><li>分区表的数据可以分布在不同的物理设备上，从而高效地利用多个硬件设备。</li><li>可以使用分区表来避免某些特殊的瓶颈，例如InnoDB的单个索引的互斥访问 、ext3文件系统的inode锁竞争等。</li><li>如果需要，还可以备份和恢复独立的分区，这在非常大的数据集的场景下效 果非常好。</li></ul><p><strong>ACID操作</strong></p><p>SELECT查询 当查询一个分区表的时候，分区层先打开并锁住所有的底层表，优化器先判断是否可以过滤部分分区，然后再调用对应的存储引擎接口访问各个分区的数据。</p><p>INSERT操作 当写入一条记录时，分区层先打开并锁住所有的底层表，然后确定哪个分区接收这条记录，再将记录写入对应底层表。</p><p>DELETE操作 当删除一条记录时，分区层先打开并锁住所有的底层表，然后确定数据对应的分区，最后对相应底层表进行删除操作。</p><p>UPDATE操作 当更新一条记录时，分区层先打开并锁住所有的底层表，MySQL先确定需要更新的记录在哪个分区，然后取出数据并更新，再判断更新后的数据应该放在哪个分区，最后对底层表进行写入操作，并对原数据所在的底层表进行删除操作。</p><p>虽然每个操作都会“先打开并锁住所有的底层表”，但这并不是说分区表在处理过程中是锁住全表的。如果存储引擎能够自己实现行级锁，例如InnoDB，则会在分区层释放对应表锁。这个加锁和解锁过程与普通InnoDB上的查询类似</p><ul><li><p><strong>Range分区</strong>：最为常用，基于属于一个给定连续区间的列值，把多行分配给分区。最常见的是基于时间字段. 基于分区的列最好是整型，如果日期型的可以使用函数转换为整型。</p></li><li><p><strong>List分区</strong>：LIST分区和RANGE分区类似，区别在于LIST是枚举值列表的集合，RANGE是连续的区间值的集合。</p></li><li><p><strong>Hash分区</strong>：基于给定的分区个数，将数据分配到不同的分区，HASH分区只能针对整数进行HASH，对于非整形的字段只能通过表达式将其转换成整数。</p></li><li><p>Key分区</p><p>：KEY分区其实跟HASH分区差不多，不同点如下：</p><ul><li>KEY分区允许多列，而HASH分区只允许一列。</li><li>如果在有主键或者唯一键的情况下，key中分区列可不指定，默认为主键或者唯一键，如果没有，则必须显性指定列。</li><li>KEY分区对象必须为列，而不能是基于列的表达式。</li><li>KEY分区和HASH分区的算法不一样，PARTITION BY HASH (expr)，MOD取值的对象是expr返回的值，而PARTITION BY KEY (column_list)，基于的是列的MD5值。</li></ul></li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><p>MySQL分区中如果存在主键或唯一键，则分区列必须包含在其中（否则判断主键或唯一时，需要扫描所有分区）</p></li><li><p>分区字段<strong>不能为<code>NULL</code></strong>，要不然怎么确定分区范围呢，所以尽量NOT NULL</p></li><li><p>最大分区数目不能超过<strong>1024</strong></p></li><li><p>不支持外键</p></li><li><p>只能对数据表的整型列进行分区，或者数据列可以通过分区函数转化成整型列</p></li><li><p>分区表<strong>不</strong>影响自增列</p></li><li><p>1、NULL值会使分区过滤无效</p></li><li><p>2、分区列和索引列不匹配（没有完全过滤分区）</p></li><li><p>3、选择分区的成本可能很高</p></li><li><p>4、维护分区的成本可能很高s</p></li><li><p>5、分区逻辑无法灵活自定义，查找分区不可控，影响高并发。</p></li><li><p>6、不合理分区会降低性能，大部分应用于历史数据存储。</p></li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><ul><li><code>A PRIMARY KEY must include all columns in the table&#39;s partitioning function</code>：这样的话判断主键是否唯一就可以在单个分区内部完成，否则就需要跨所有的分区</li><li><code>MAXVALUE can only be used in last partition definition</code>：RANGE表分区后不能带MAXVALUE分区，否则无法增加分区。或者就只能重新分区了</li><li><code>Table has no partition for value 737425</code>：因为分区的范围没有包含所有可能的记录的值</li></ul><h2 id="_10-对已有表进行分区" tabindex="-1">10.对已有表进行分区 <a class="header-anchor" href="#_10-对已有表进行分区" aria-label="Permalink to &quot;10.对已有表进行分区&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>CREATE TABLE \`student\`</span></span>
<span class="line"><span>(</span></span>
<span class="line"><span>    \`id\`         int(11) unsigned NOT NULL AUTO_INCREMENT,</span></span>
<span class="line"><span>    \`name\`       varchar(20) NOT NULL DEFAULT &#39;&#39;,</span></span>
<span class="line"><span>    \`age\`        int(4) NOT NULL,</span></span>
<span class="line"><span>    \`uid\`        int(4) NOT NULL DEFAULT &#39;0&#39;,</span></span>
<span class="line"><span>    \`created_at\` datetime    NOT NULL DEFAULT CURRENT_TIMESTAMP,</span></span>
<span class="line"><span>    \`start_date\` date        NOT NULL DEFAULT &#39;0000-00-00&#39;,</span></span>
<span class="line"><span>    PRIMARY KEY (\`id\`, \`uid\`)</span></span>
<span class="line"><span>) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**http://mysql.taobao.org/monthly/2017/11/09/**/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**创建分区**/</span></span>
<span class="line"><span>ALTER TABLE student PARTITION BY RANGE COLUMNS(uid)(</span></span>
<span class="line"><span>    PARTITION p2 VALUES LESS THAN (10),</span></span>
<span class="line"><span>    PARTITION p3 VALUES LESS THAN (20),</span></span>
<span class="line"><span>    PARTITION p4 VALUES LESS THAN (30),</span></span>
<span class="line"><span>    PARTITION p5 VALUES LESS THAN (40),</span></span>
<span class="line"><span>    PARTITION po VALUES LESS THAN (MAXVALUE)</span></span>
<span class="line"><span>);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**新增分区**/</span></span>
<span class="line"><span>alter table student add partition(</span></span>
<span class="line"><span>    partition p6 VALUES LESS THAN (50)</span></span>
<span class="line"><span>);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**删除分区**/</span></span>
<span class="line"><span>alter table student drop partition p6;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**拆分分区**/</span></span>
<span class="line"><span>alter table student reorganize partition p5 into(</span></span>
<span class="line"><span>    partition s0 VALUES LESS THAN (45),</span></span>
<span class="line"><span>    partition s1 VALUES LESS THAN (47)</span></span>
<span class="line"><span>);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/**合并分区**/</span></span>
<span class="line"><span>alter table student reorganize partition s0,s1 into (</span></span>
<span class="line"><span>    partition p6 VALUES LESS THAN(60)</span></span>
<span class="line"><span>);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br></div></div><h4 id="range-支持类型" tabindex="-1">Range 支持类型 <a class="header-anchor" href="#range-支持类型" aria-label="Permalink to &quot;Range 支持类型&quot;">​</a></h4><ul><li>DATE，DATETIME，TIMESTAMP。</li><li>支持 year，month，day 函数，函数为空和 day 函数一样。</li><li>TINYINT, SMALLINT, MEDIUMINT, INT, BIGINT。</li><li>支持 year，month，day 函数，此时传入的值转换为年月日，然后和分表信息进行对比。</li></ul><h4 id="list-支持类型" tabindex="-1">List 支持类型 <a class="header-anchor" href="#list-支持类型" aria-label="Permalink to &quot;List 支持类型&quot;">​</a></h4><ul><li>DATE，DATETIME，TIMESTAMP。</li><li>支持年月日函数。</li><li>TINYINT, SMALLINT, MEDIUMINT, INT , BIGINT。</li></ul><p>警告</p><p>建议不要使用 TIMESTAMP 类型作为分区键，因为 TIMESTAMP 受到时区的影响，同时只能使用到2038年。</p><p>如果分区键是 char 或者 varchar 类型，建议长度不超255。</p><p>建议业务尽量都使用一级分区表。</p><ul><li>使用前根据业务长期场景合理设计表结构，二级分区适用于表结构创建后长期都不需要 DDL 变更、需要定期进行分区数据清理和裁剪的场景，如日志流水表。</li><li>合理设计二级分区的粒度，二级分区的粒度建议不要划分得太细，避免产生过多的二级子表。如流水表按月进行二级分区，而不是按天/小时进行分区，避免文件系统上数据文件个数过多。</li><li>在对二级分区表进行 SQL 查询时，查询条件需要尽量带上一级分区和二级分区的键值，避免执行查询时需要打开很多的数据文件进行搜索。</li><li>在对二级分区表进行 join 查询时，如果查询条件未能带上一级分区和二级分区的键值，操作性能效率较低，建议不要使用。</li><li>表的主键或唯一索引需要包含分区键，否则无法保证数据唯一性。</li></ul>`,28);function u(s,d,T,m,A,E){return r(),l("div",null,[n("h1",c,[p(e(s.$frontmatter.title)+" ",1),o]),b])}const N=a(t,[["render",u]]);export{h as __pageData,N as default};
